SELECT AVG(value) AS average_measurement
FROM phenotypic_measurements
WHERE experiment_id = 1 AND stage_id = 1;

SELECT AVG(value) AS average_measurement
FROM phenotypic_measurements
WHERE stage_id = 1;

SELECT AVG(value) AS average_value
FROM phenotypic_measurements
WHERE stage_id = 1;

SELECT COUNT(*) AS note_count
FROM experiment_notes
WHERE experiment_id = 1;

SELECT MIN(value) AS min_measurement_value
FROM phenotypic_measurements
WHERE experiment_id = 1;

SELECT type_name
FROM phenotypic_measurement_types
WHERE type_id = 0;

SELECT experiment_name
FROM experiments
ORDER BY experiment_name;

SELECT AVG(value) AS average_value
FROM phenotypic_measurements
WHERE experiment_id = 1;
